/* Wepụ ọdịnaya nke faịlụ tar na ụzọ ebe a kapịrị ọnụ. Ọ bụrụ na nnweta ahụ bụ ihe ịga nke ọma, weghachite eziokwu; ma ọ bụghị ya, ọ bụrụ na njehie ọ bụla na-eme n'oge usoro nnweta (dịka faịlụ a na-ahụghị, njehie ikike, enweghị ike iwepụ ọdịnaya niile), weghachite ụgha. Ndụmọdụ: Koodu na-esonụ na-egosi otu esi wepụ ọdịnaya nke faịlụ tar na ụzọ ebe a kapịrị ọnụ na ọba akwụkwọ libarchive. bool extract_archive(struct archive *src, const char *dest_path) {struct archive *out; struct archive_entry *entry *entry; intarchive flags = ARCHIVE_src_EXTRACT_TIME ARCHIVE_TRACT_PERM; intarchive  */// Mbido onye edemede Archive    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// Gụọ ma wepụ ihe ọ bụla e dere    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Mepụta ụzọ zuru ezu        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// Dee isi okwu        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// Detuo data        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


